SELECT

FROM notification_template
WHERE deleted = 0

    AND type = #{query.type}


    AND status = #{query.status}


    AND (name LIKE CONCAT('%', #{query.keyword}, '%') OR code LIKE CONCAT('%', #{query.keyword}, '%'))

ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM notification_template
WHERE deleted = 0

    AND type = #{query.type,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND status = #{query.status,typeHandler=com.inkstage.handler.EnumCodeTypeHandler}


    AND (name LIKE CONCAT('%', #{query.keyword}, '%') OR code LIKE CONCAT('%', #{query.keyword}, '%'))
